import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { studentsAPI } from '../../services/api';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';
import toast from 'react-hot-toast';
import { User, Camera, Save } from 'lucide-react';

const StudentProfile = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [formData, setFormData] = useState({});

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      // Get student profile by user_id
      const response = await studentsAPI.getById(user.id);
      if (response.data.success) {
        setProfile(response.data.student);
        setFormData(response.data.student);
      }
    } catch (error) {
      console.error('Error fetching profile:', error);
      toast.error('Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await studentsAPI.update(profile.id, formData);
      toast.success('Profile updated successfully');
      setEditMode(false);
      fetchProfile();
    } catch (error) {
      toast.error('Failed to update profile');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-secondary-800">My Profile</h1>
        <button
          onClick={() => setEditMode(!editMode)}
          className={`px-4 py-2 rounded-lg font-medium transition-colors ${
            editMode
              ? 'bg-secondary-200 text-secondary-700'
              : 'bg-primary-600 text-white hover:bg-primary-700'
          }`}
        >
          {editMode ? 'Cancel' : 'Edit Profile'}
        </button>
      </div>

      {/* Profile Form */}
      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Profile Picture */}
          <Card>
            <div className="text-center">
              <div className="w-32 h-32 bg-primary-100 rounded-full mx-auto mb-4 flex items-center justify-center overflow-hidden">
                {profile?.profile_picture ? (
                  <img
                    src={profile.profile_picture}
                    alt="Profile"
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <User className="w-16 h-16 text-primary-400" />
                )}
              </div>
              <p className="text-secondary-600 font-medium">
                {profile?.first_name} {profile?.last_name}
              </p>
              <p className="text-secondary-500 text-sm">{profile?.student_id}</p>
            </div>
          </Card>

          {/* Personal Information */}
          <Card title="Personal Information" className="lg:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="label">First Name</label>
                <input
                  type="text"
                  name="first_name"
                  value={formData.first_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Middle Name</label>
                <input
                  type="text"
                  name="middle_name"
                  value={formData.middle_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Last Name</label>
                <input
                  type="text"
                  name="last_name"
                  value={formData.last_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Gender</label>
                <select
                  name="gender"
                  value={formData.gender || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                >
                  <option value="">Select Gender</option>
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Other">Other</option>
                </select>
              </div>
              <div>
                <label className="label">Contact Number</label>
                <input
                  type="text"
                  name="contact_number"
                  value={formData.contact_number || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Email</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div className="md:col-span-2">
                <label className="label">Address</label>
                <textarea
                  name="address"
                  value={formData.address || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  rows={2}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
            </div>
          </Card>

          {/* Guardian Information */}
          <Card title="Guardian Information">
            <div className="space-y-4">
              <div>
                <label className="label">Guardian Name</label>
                <input
                  type="text"
                  name="guardian_name"
                  value={formData.guardian_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Guardian Contact</label>
                <input
                  type="text"
                  name="guardian_contact"
                  value={formData.guardian_contact || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
            </div>
          </Card>

          {/* Academic Information */}
          <Card title="Academic Information">
            <div className="space-y-4">
              <div>
                <label className="label">Year Level</label>
                <input
                  type="text"
                  value={profile?.year_level || 'N/A'}
                  disabled
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Section</label>
                <input
                  type="text"
                  value={profile?.section || 'N/A'}
                  disabled
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Status Record</label>
                <input
                  type="text"
                  value={profile?.status_record || 'N/A'}
                  disabled
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
            </div>
          </Card>

          {/* Work Information */}
          <Card title="Work Information">
            <div className="space-y-4">
              <div>
                <label className="label">Working Student</label>
                <select
                  name="working_student"
                  value={formData.working_student || 'No'}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                >
                  <option value="No">No</option>
                  <option value="Yes">Yes</option>
                </select>
              </div>
              {formData.working_student === 'Yes' && (
                <div>
                  <label className="label">Type of Work</label>
                  <input
                    type="text"
                    name="work_type"
                    value={formData.work_type || ''}
                    onChange={handleChange}
                    disabled={!editMode}
                    className="input-field disabled:bg-secondary-50"
                  />
                </div>
              )}
            </div>
          </Card>
        </div>

        {editMode && (
          <div className="mt-6 flex justify-end">
            <button
              type="submit"
              disabled={saving}
              className="btn-primary flex items-center gap-2"
            >
              <Save className="w-4 h-4" />
              {saving ? 'Saving...' : 'Save Changes'}
            </button>
          </div>
        )}
      </form>
    </div>
  );
};

export default StudentProfile;
